"use client";
import React from "react";
import Box, { BoxProps } from "@mui/material/Box";
import { SxProps, Theme } from "@mui/material/styles";
import { getBaseGrey } from "./utils";

const createTypography = (generateSx: () => BoxProps["sx"]) => {
  const Component = ({
    cached,
    sx = [],
    ...props
  }: { cached?: boolean } & BoxProps) => {
    const ref = React.useRef(generateSx());
    const resolvedSx: SxProps<Theme> =
      (cached ? ref.current : generateSx()) || [];
    return (
      <Box
        {...props}
        sx={[
          {
            height: 16,
            borderRadius: 1,
            bgcolor: getBaseGrey,
          },
          ...(Array.isArray(resolvedSx) ? resolvedSx : [resolvedSx]),
          ...(Array.isArray(sx) ? sx : [sx]),
        ]}
      />
    );
  };
  return Component;
};

export const H1 = createTypography(() => ({
  height: 40,
  width: "16ch",
  maxWidth: "100%",
  mt: 3,
  mb: 1,
}));

export const Text = createTypography(() => ({
  height: 16,
  mt: 1.5,
  mb: 1.5,
  width: "100%",
  maxWidth: "100%",
}));

export const Word = createTypography(() => ({
  height: 16,
  width: "10ch",
  maxWidth: "100%",
}));

"use client";
import { Theme } from "@mui/material/styles";

export const getBaseGrey = (theme: Theme): string =>
  theme.palette.mode === "dark" ? "rgba(255,255,255,0.12)" : "grey.300";

export const getLightGrey = (theme: Theme): string =>
  theme.palette.mode === "dark" ? "rgba(255,255,255,0.09)" : "grey.200";

export const getLightestGrey = (theme: Theme): string =>
  theme.palette.mode === "dark" ? "rgba(255,255,255,0.07)" : "grey.50";

let seed = 0;
function seededRandom() {
  seed = (seed * 9301 + 49297) % 233280;
  return seed / 233280;
}

export const randomBetween = (min: number, max: number, unit?: string) => {
  const result = Math.floor(seededRandom() * (max - min)) + min;
  if (unit) return `${result}${unit}`;
  return result;
};

